1	type Item = { type: string };
2	
3	type QuoteStep = { op: "quote"; items: Item[] };
4	
5	export type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Array<Record<string, unknown>>;
8	};
9	
10	export type ScenarioResult = {
11	  results: Array<Record<string, unknown>>;
12	};
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
26	
27	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const BLOCK_SIZE = 3;
31	const BLOCK_PREMIUM = 60;
32	
33	const baseTotalFor = (items: Item[]): number => {
34	  const mains = items.filter((item) => !COMPONENT_TYPES.has(item.type));
35	  let total = mains.reduce((sum, item) => sum + basePremiumFor(item), 0);
36	  const componentsByType: Record<string, Item[]> = {};
37	  for (const item of items) {
38	    if (!COMPONENT_TYPES.has(item.type)) continue;
39	    (componentsByType[item.type] ??= []).push(item);
40	  }
41	  for (const group of Object.values(componentsByType)) {
42	    if (group.length === BLOCK_SIZE) {
43	      total += BLOCK_PREMIUM;
44	    } else {
45	      total += group.reduce((sum, item) => sum + basePremiumFor(item), 0);
46	    }
47	  }
48	  return total;
49	};
50	
51	const quotePremium = (items: Item[]): number => {
52	  const baseTotal = baseTotalFor(items);
53	  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
54	  return Math.ceil(baseTotal + firstInsuranceSurcharge + PROCESSING_FEE);
55	};
56	
57	export const runScenario = (scenario: Scenario): ScenarioResult => {
58	  const results = scenario.steps.map((step) => {
59	    const quote = step as unknown as QuoteStep;
60	    return { premium: quotePremium(quote.items) };
61	  });
62	  return { results };
63	};
